class Solution {
public:
    int missingNumber(vector<int>& nums) {
        int n = nums.size();
        int sum1 = 0, sum2 = 0;

        // Sum of array elements
        for (int i = 0; i < n; i++) {
            sum1 += nums[i];
        }

        // Sum of numbers from 0 to n
        for (int i = 0; i <= n; i++) {
            sum2 += i;
        }

        // Missing number is the difference
        return abs(sum2 - sum1);
    }
};

